#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long a1 = 500 - 2*X; if(a1 < 0) a1 = 0;
        long long b1 = 1000 - 4*(X+Y); if(b1 < 0) b1 = 0;
        long long ans1 = a1 + b1;
        long long b2 = 1000 - 4*Y; if(b2 < 0) b2 = 0;
        long long a2 = 500 - 2*(X+Y); if(a2 < 0) a2 = 0;
        long long ans2 = b2 + a2;
        long long ans = ans1 > ans2 ? ans1 : ans2;
        printf("%lld\n", ans);
    }
    return 0;
}

